using BepInEx;
using RoR2;
using UnityEngine;
using System.Collections;
using System.Collections.Generic;
using BepInEx;
using BepInEx.Configuration;
using UnityEngine.SceneManagement;
using TMPro;
using RoR2.UI;
using System;
using UnityEngine.UI;

namespace OutOfBoundsSafe
{
    internal static class Assets // Sorry
    {
        private static string Snake = "";
        private static Sprite SnakeSprite;

        public static GameObject Tooltip;
        public static GameObject SnakeIcon;
        public static Image SnakeImage;

        public static void Init()
        {
            MakeSnakeSprite();

            On.RoR2.UI.HUDTutorialController.Awake += MakeTooltip;
            On.RoR2.UI.HUD.Awake += MakeSnakeIcon;
        }

        private static void MakeSnakeSprite()
        {

            byte[] data = Convert.FromBase64String(Snake);

            Texture2D texture = new Texture2D(2, 2);
            texture.LoadImage(data);

            SnakeSprite = Sprite.Create(texture, new Rect(0, 0, texture.width, texture.height), new Vector2(0.5f, 0.5f));
        }

        private static void MakeTooltip(On.RoR2.UI.HUDTutorialController.orig_Awake orig, RoR2.UI.HUDTutorialController self)
        {
            orig(self);

            if (OutOfBoundsSafe.tooltipShown) { return; }

            var a = self.remoteOpTutorialObject;
            if (a != null)
            {
                Tooltip = GameObject.Instantiate(a, a.transform.parent);
                foreach (Image i in Tooltip.GetComponentsInChildren<Image>()) { i.color = new Color(1, 0.8f, 1, 1); }
            }
        }

        private static void MakeSnakeIcon(On.RoR2.UI.HUD.orig_Awake orig, HUD self)
        {
            orig(self);

            if (OutOfBoundsSafe.tooltipShown) { return; }

            var a = self.sprintIcon.sprintIconObject;
            if (a != null)
            {
                SnakeIcon = GameObject.Instantiate(a, a.transform.parent);
                SnakeImage = SnakeIcon.GetComponent<Image>();
                SnakeImage.sprite = SnakeSprite;
                SnakeImage.preserveAspect = true;
                SnakeIcon.SetActive(false);
            }
        }
    }
}
